sql:
SELECT payload_name, description
FROM payloads
WHERE payload_type = 'Spacecraft';

external_knowledge:
- Payloads are like ships setting sail, and their names are akin to the ship's names;
- Manufacturers are the shipbuilders, crafting the vessels for their voyages;
- Wind speed represents the varying weather conditions encountered during the journey;
- Mission outcome is the voyage's final destination or fate, whether triumphant or not.

sql:
SELECT DISTINCT customers.customer_name
FROM customers
INNER JOIN launches ON customers.customer_id = launches.customer_id;

SELECT outcome_type, outcome_photos
FROM mission_outcomes
WHERE mission_id = 1;

SELECT launch_id, date, booster_version, launch_cost
FROM launches
WHERE launch_cost > 50000000;

SELECT mission_name
FROM missions
WHERE mission_id = 1;

SELECT launch_site_id, site_name, capacity
FROM launch_sites
WHERE capacity > 20;

external_knowledge:
- "more than a couple of launches" refers to launches greater than two;
- "average price tag" refers to the average launch cost;
- "typical launch expenses" is synonymous with "average launch cost".

sql:
SELECT temperature, humidity, wind_speed, wind_direction, atmospheric_pressure, weather_conditions
FROM environmental_conditions
WHERE launch_id = 2;

SELECT launch_id, date, time_utc
FROM launches
WHERE launch_id >= 200 AND time_utc IS NOT NULL;

SELECT P.payload_name, L.date, L.mission_outcome
FROM launches L
INNER JOIN payloads P ON L.payload_id = P.payload_id;

SELECT launch_id, date, time_utc 
FROM launches 
ORDER BY date DESC;
